import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/installer-screen.Db0E_BrK.js";import{t as a}from"./chunks/updating-fabric.1C0PZ95m.js";import{t as o}from"./chunks/macos-downloads.DCRwPSpe.js";const s=JSON.parse(`{"title":"Aktualisieren von Fabric","description":"Eine Schritt-für-Schritt-Anleitung zum Aktualisieren von Fabric.","frontmatter":{"title":"Aktualisieren von Fabric","description":"Eine Schritt-für-Schritt-Anleitung zum Aktualisieren von Fabric.","authors":["IMB11","modmuss50"],"files":[]},"headers":[],"relativePath":"de_de/1.21.8/players/updating-fabric.md","filePath":"versions/1.21.8/translated/de_de/players/updating-fabric.md","lastUpdated":1760721669000}`);var c={name:`de_de/1.21.8/players/updating-fabric.md`};function l(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Aktualisieren von Fabric <a class="header-anchor" href="#h1" aria-label="Permalink to “Aktualisieren von Fabric”">​</a></h1><p>Diese Anleitung wird das Aktualisieren von Fabric detailliert für den Minecraft-Launcher erklären.</p><p>Für die Launcher von Drittanbietern solltest du deren Dokumentation verwenden.</p><p>Das Vorgehen beim Aktualisieren von Fabric ist der Installation ähnlich, deshalb werden sich Teile dieser Anleitung mit der Anleitung <a href="./installing-fabric">Installation von Fabric</a> überschneiden.</p><h2 id="why-should-i-update-fabric-loader" tabindex="-1">Warum sollte ich den Fabric-Loader aktualisieren? <a class="header-anchor" href="#why-should-i-update-fabric-loader" aria-label="Permalink to “Warum sollte ich den Fabric-Loader aktualisieren?”">​</a></h2><p>Neuere Mods können eine neuere Version des Fabric-Loaders benötigen, um zu funktionieren, weshalb es wichtig ist, ihn auf dem neuesten Stand zu halten, um immer die neuesten Mods benutzen zu können.</p><p>Dieser Leitfaden bezieht sich ausschließlich auf den offiziellen Minecraft Launcher. Für die Launcher von Drittanbietern solltest du deren Dokumentation verwenden.</p><h2 id="1-download-the-fabric-installer" tabindex="-1">1. Herunterladen des Fabric-Installers <a class="header-anchor" href="#1-download-the-fabric-installer" aria-label="Permalink to “1. Herunterladen des Fabric-Installers”">​</a></h2><p>Der Fabric-Installer kann von der <a href="https://fabricmc.net/use/" target="_blank" rel="noreferrer">Fabric-Webseite</a> heruntergeladen werden.</p><p>Wenn du Windows verwendest, lade die <code>.exe</code>-Version (<code>Download For Windows</code>) herunter, da sie keine Java-Installation auf dem System benötigt. Stattdessen wird die Java-Installation des offiziellen Launchers verwendet.</p><p>Für macOS und Linux solltest du die <code>.jar</code>-Version verwenden. Manchmal musst du Java vor diesem Schritt installieren.</p><h2 id="2-run-the-fabric-installer" tabindex="-1">2. Ausführen des Fabric-Installers <a class="header-anchor" href="#2-run-the-fabric-installer" aria-label="Permalink to “2. Ausführen des Fabric-Installers”">​</a></h2><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Schließe vor dem Ausführen des Installers zuerst Minecraft und den Minecraft Launcher.</p></div><details class="details custom-block"><summary>Informationen für macOS-Nutzer</summary><p>Auf macOS musst du möglicherweise zuerst einen Rechtsklick auf die <code>.jar</code>-Datei im Downloads-Verzeichnis machen, und <code>Öffnen</code> zum Ausführen klicken.</p><p><img src="/assets/players/installing-fabric/macos-downloads.png" alt="MacOS Kontextmenü im Fabric-Installer" loading="lazy"></p><p>Bei der Frage &quot;Möchten Sie es wirklich öffnen?&quot;, klicke erneut auf <code>Öffnen</code>.</p></details><p>Wenn du den Installer geöffnet hast, sollte diese Oberfläche erscheinen:</p><p><img src="/assets/players/installing-fabric/installer-screen.png" alt="Fabric-Installer mit &quot;Installieren&quot; hervorgehoben" loading="lazy"></p><p>Um Fabric zu aktualisieren, vergewissere dich einfach, dass die Spielversion und die Loader-Version korrekt sind, und klicke dann auf <code>Installieren</code>.</p><div class="warning custom-block"><p class="custom-block-title">WICHTIG</p><p>Stelle sicher, dass du die Option <code>Profil erstellen</code> deaktivierst, wenn du das Installationsprogramm ausführst, da sonst ein neues Profil erstellt wird, das wir in diesem Fall nicht benötigen.</p></div><h2 id="3-open-the-profile-in-the-minecraft-launcher" tabindex="-1">3. Öffne das Profil im Minecraft Launcher <a class="header-anchor" href="#3-open-the-profile-in-the-minecraft-launcher" aria-label="Permalink to “3. Öffne das Profil im Minecraft Launcher”">​</a></h2><p>Sobald der Installer fertig ist, kannst du den Minecraft Launcher öffnen und auf die Registerkarte <code>Installationen</code> gehen. Gehe zu deinem Fabric-Profil und öffne den Bearbeitungsbildschirm.</p><p>Ersetze die Version durch die neue Version von Fabric Loader, die du gerade installiert hast, und drücke <code>Speichern</code>.</p><p><img src="/assets/players/updating-fabric.png" alt="Aktualisieren der Fabric Loader Version im Minecraft Launcher" loading="lazy"></p><h2 id="4-you-re-done" tabindex="-1">4. Du hast es geschafft! <a class="header-anchor" href="#4-you-re-done" aria-label="Permalink to “4. Du hast es geschafft!”">​</a></h2><p>Sobald du die Schritte abgeschlossen hast, kannst du zur Registerkarte <code>Spielen</code> zurückkehren, das Fabric-Profil aus dem Dropdown-Menü in der linken unteren Ecke auswählen und auf <code>Spielen</code> drücken!</p><p>Wenn du beim Befolgen dieses Leitfadens auf Probleme stößt, kannst du im <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Fabric Discord</a> im Kanal <code>#player-support</code> um Hilfe bitten.</p>`,25)]])}var u=r(c,[[`render`,l]]);export{s as __pageData,u as default};